external_knowledge:
- Shining stars are metaphors for top-performing players;
- Illuminate is used metaphorically to describe players significantly contributing to their team's achievements;
- The phrase 'scorched into the back of the net' is a vivid way to describe scoring goals.

sql:
SELECT MAX(accuracy) AS Maximum_Accuracy
FROM performance_metrics
WHERE game_id = 0;

SELECT p.player_name, t.team_name
FROM players p
JOIN teams t ON p.team_id = t.team_id;

SELECT player_name
FROM players
WHERE player_id IN (
  SELECT player_id
  FROM performance_metrics
);

SELECT player_name
FROM players
WHERE team_id != 0;
